// ==================================================
//  pages/AIGenerator.jsx — توليد تصميم بالذكاء الاصطناعي
// ==================================================
import React, { useState } from 'react'
import { generateAIDesign, generateVariations } from '../services/designService'

const SUGGESTIONS = [
  'فستان سهرة أزرق بأكمام طويلة وتطريز ذهبي',
  'عباءة سوداء عصرية بتفاصيل بيضاء',
  'قميص كاجوال بنقشة زهور ألوان فاتحة',
  'بدلة رسمية رمادية للرجال',
  'فستان صيفي قصير بألوان استوائية',
]

export default function AIGenerator() {
  const [prompt, setPrompt]         = useState('')
  const [images, setImages]         = useState([])
  const [loading, setLoading]       = useState(false)
  const [error, setError]           = useState('')
  const [mode, setMode]             = useState('single')  // single | variations
  const [selected, setSelected]     = useState(null)
  const [image, setImage] = useState(null)

  const generate = async () => {
    if (!prompt.trim()) return setError('اكتب وصف التصميم أولاً')
    setError('')
    setImages([])
    setSelected(null)
    setLoading(true)

    try {
      if (mode === 'single') {
        const formData = new FormData()
        formData.append('message', prompt)
        if (image) formData.append('image', image)
       const data= await API.post('/ai/chat/', formData)
        setImages([data.image_url])
       }
      else {
        const data = await generateVariations(prompt, 3)
        setImages(data.images)
      }
    } catch {
      setError('حدث خطأ في التوليد — تأكد من مفتاح OpenAI في settings.py')
      // بيانات تجريبية للعرض
      setImages(['https://via.placeholder.com/400x400/f5f0e8/c9a84c?text=تصميم+1'])
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h1 style={styles.title}>🤖 مولّد التصاميم</h1>
        <p style={styles.sub}>صف تصميمك وشاهد الذكاء الاصطناعي يبدع</p>
      </div>

      <div style={styles.layout}>
        {/* جانب الإدخال */}
        <div style={styles.inputSide}>

          {/* اختيار الوضع */}
          <div style={styles.modeRow}>
            <button
              onClick={() => setMode('single')}
              className="btn"
              style={{ ...styles.modeBtn, background: mode === 'single' ? '#0a0a0a' : '#fff', color: mode === 'single' ? '#fff' : '#333' }}
            >
              تصميم واحد
            </button>
            <button
              onClick={() => setMode('variations')}
              className="btn"
              style={{ ...styles.modeBtn, background: mode === 'variations' ? '#0a0a0a' : '#fff', color: mode === 'variations' ? '#fff' : '#333' }}
            >
              3 تنويعات
            </button>
          </div>

          {/* حقل الوصف */}
          <label style={styles.label}>صف تصميمك</label>
          {/* زر رفع الصورة */}
<label style={styles.uploadBtn}>
  📎 {image ? image.name : 'رفع صورة للإلهام'}
  <input
    type="file"
    accept="image/*"
    style={{ display: 'none' }}
    onChange={e => setImage(e.target.files[0])}
  />
</label>

{/* معاينة الصورة */}
{image && (
  <div style={{ position: 'relative', marginBottom: 12 }}>
    <img
      src={URL.createObjectURL(image)}
      alt="preview"
      style={{ width: '100%', borderRadius: 12, maxHeight: 200, objectFit: 'cover' }}
    />
    <button
      onClick={() => setImage(null)}
      style={{ position: 'absolute', top: 8, right: 8, background: 'red', color: '#fff', border: 'none', borderRadius: '50%', width: 28, height: 28, cursor: 'pointer' }}
    >
      ✕
    </button>
  </div>
)}
          <textarea
            value={prompt}
            onChange={e => setPrompt(e.target.value)}
            placeholder="مثال: فستان سهرة أحمر بأكمام قصيرة وتطريز ذهبي عند الخصر..."
            className="input"
            rows={5}
            style={{ resize: 'none', marginBottom: 16 }}
          />

          {/* اقتراحات */}
          <p style={styles.suggestLabel}>💡 اقتراحات سريعة:</p>
          <div style={styles.suggestions}>
            {SUGGESTIONS.map((s, i) => (
              <button
                key={i}
                onClick={() => setPrompt(s)}
                style={styles.suggestion}
              >
                {s}
              </button>
            ))}
          </div>

          {error && <p className="msg-error" style={{marginBottom: 12}}>{error}</p>}

          <button
            onClick={generate}
            className="btn btn-gold"
            style={{ width: '100%', padding: 14, fontSize: 16, marginTop: 8 }}
            disabled={loading}
          >
            {loading ? '⏳ جاري التوليد...' : '✨ ولّد التصميم'}
          </button>

          {/* معلومة */}
          <p style={styles.note}>
            ⚠️ كل طلب يستهلك رصيداً من OpenAI — كن دقيقاً في وصفك
          </p>
        </div>

        {/* جانب النتيجة */}
        <div style={styles.resultSide}>
          {loading && (
            <div style={styles.loadingBox}>
              <div className="spinner" />
              <p style={{ color: '#888', marginTop: 16 }}>الذكاء الاصطناعي يرسم تصميمك...</p>
            </div>
          )}

          {!loading && images.length === 0 && (
            <div style={styles.placeholder}>
              <span style={{ fontSize: 80 }}>🎨</span>
              <p style={{ color: '#bbb', marginTop: 16 }}>نتيجة التصميم ستظهر هنا</p>
            </div>
          )}

          {!loading && images.length > 0 && (
            <div>
              <h3 style={styles.resultTitle}>
                {images.length === 1 ? 'تصميمك الجديد' : `${images.length} تنويعات`}
              </h3>
              <div style={{ display: 'grid', gridTemplateColumns: images.length === 1 ? '1fr' : 'repeat(auto-fill, minmax(200px, 1fr))', gap: 16 }}>
                {images.map((img, i) => (
                  <div
                    key={i}
                    onClick={() => setSelected(img)}
                    style={{
                      ...styles.resultCard,
                      border: selected === img ? '3px solid #c9a84c' : '3px solid transparent'
                    }}
                  >
                    <img src={img} alt={`تصميم ${i+1}`} style={{ width: '100%', borderRadius: 12 }} />
                    <p style={styles.imgLabel}>تصميم {i+1}</p>
                  </div>
                ))}
              </div>

              {selected && (
                <div style={{ marginTop: 20, display: 'flex', gap: 12 }}>
                  <a
                    href={selected}
                    download="fashion-design.png"
                    className="btn btn-primary"
                    style={{ flex: 1, textAlign: 'center', padding: 12 }}
                  >
                    ⬇️ تحميل
                  </a>
                  <button className="btn btn-gold" style={{ flex: 1, padding: 12 }}>
                    💾 حفظ في تصاميمي
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

const styles = {
  page:        { padding: '48px 60px', maxWidth: 1100, margin: '0 auto' },
  header:      { textAlign: 'center', marginBottom: 48 },
  title:       { fontFamily: "'Playfair Display',serif", fontSize: 42, marginBottom: 12 },
  sub:         { color: '#888', fontSize: 16 },
  layout:      { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 40 },
  inputSide:   { background: '#fff', borderRadius: 20, padding: 32, boxShadow: '0 4px 20px rgba(0,0,0,0.07)' },
  modeRow:     { display: 'flex', gap: 10, marginBottom: 24 },
  modeBtn:     { flex: 1, padding: '10px 0', borderRadius: 10, border: '1.5px solid #ddd', cursor: 'pointer', fontSize: 14 },
  label:       { display: 'block', fontWeight: 500, marginBottom: 8, fontSize: 15 },
  suggestLabel:{ fontSize: 13, color: '#888', marginBottom: 10 },
  suggestions: { display: 'flex', flexWrap: 'wrap', gap: 8, marginBottom: 16 },
  suggestion:  { padding: '6px 14px', background: '#f5f0e8', border: 'none', borderRadius: 20, cursor: 'pointer', fontSize: 12, color: '#555' },
  note:        { fontSize: 12, color: '#aaa', marginTop: 14, textAlign: 'center' },
  resultSide:  { background: '#fff', borderRadius: 20, padding: 32, boxShadow: '0 4px 20px rgba(0,0,0,0.07)', display: 'flex', flexDirection: 'column', justifyContent: 'center' },
  loadingBox:  { textAlign: 'center', padding: '60px 0' },
  placeholder: { textAlign: 'center', padding: '60px 0' },
  resultTitle: { fontFamily: "'Playfair Display',serif", fontSize: 22, marginBottom: 20 },
  resultCard:  { cursor: 'pointer', borderRadius: 14, overflow: 'hidden', transition: 'transform 0.2s' },
  imgLabel:    { textAlign: 'center', marginTop: 8, fontSize: 13, color: '#888' },
  uploadBtn: {
  display: 'block',
  padding: '10px 16px',
  background: '#f5f0e8',
  border: '2px dashed #c9a84c',
  borderRadius: 12,
  cursor: 'pointer',
  textAlign: 'center',
  marginBottom: 12,
  fontSize: 14,
  color: '#666'
},
}
